              isDisabled={isLoadingRefiners}
            >
              Refresh
            </Button>
          </div>

          {isLoadingRefiners ? (
            <div className="flex justify-center items-center p-8">
              <Spinner size="lg" />
              <span className="ml-3">Loading refiners...</span>
            </div>
          ) : refiners.length === 0 ? (
            <EmptyState
              icon={<Brain className="h-8 w-8" />}
              title="No refiners found"
