                        showExternalLink={true}
                        className="text-small"
                      />
                    </TableCell>
                    <TableCell>
                      <Chip size="sm" variant="flat">
                        Schema #{refiner.schemaId}
                      </Chip>
                    </TableCell>
                    <TableCell>
                      <Button
                        as="a"
                        href={refiner.refinementInstructionUrl}
                        target="_blank"
                        rel="noopener noreferrer"
                        size="sm"
                        variant="flat"
                        startContent={<ExternalLink className="h-3 w-3" />}
                      >
                        Download Instructions
                      </Button>
                    </TableCell>
                    <TableCell>
                      {refiner.source && (
                        <Chip
                          size="sm"
                          color={
                            refiner.source === "created" ? "success" : "default"
                          }
                          variant="flat"
                        >
                          {refiner.source}
                        </Chip>
                      )}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>

            {/* Refiners Pagination */}
            {refiners.length > REFINERS_PER_PAGE && (
              <div className="flex justify-center mt-4">
                <Pagination
                  total={refinersTotalPages}
                  page={refinersCurrentPage}
                  onChange={setRefinersCurrentPage}
                  showControls={true}
