                Showing {paginatedRefiners.length} of {refiners.length} refiners
                {refiners.length > REFINERS_PER_PAGE && (
                  <span className="ml-2">
                    • Page {refinersCurrentPage} of {refinersTotalPages}
                  </span>
                )}
              </div>
            )}
          )}
        </div>
      </div>
    </section>
  );
